      CREATE OR REPLACE FUNCTION notify_hl7_patient_merge_undo()
RETURNS TRIGGER AS $function$
      BEGIN
      INSERT INTO ${hl7.integrationSchema}.hl7_event (
        id,
        event_type,
        object_key,
        event_datetime
      )
      VALUES (
               gen_random_uuid()::varchar,
               '${hl7.events.patientMergedUndo}',
               NEW.id::varchar,
               NOW()
             );

      RETURN NEW;
      END;
      $function$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_hl7_patient_merge_undo ON patient_merge_logs;

CREATE TRIGGER trg_hl7_patient_merge_undo
  AFTER UPDATE OF merge_status ON patient_merge_logs
  FOR EACH ROW
  WHEN (
  NEW.merge_status = 'UNDO'
  AND OLD.merge_status IS DISTINCT FROM NEW.merge_status
  )
  EXECUTE FUNCTION notify_hl7_patient_merge_undo();
